using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;
using TestProject.Models;
using TestProject.Services;

namespace TestProject.Controllers;

/// <summary>
/// HTTP API surface for the path-safe file system operations exposed by
/// <see cref="IFileService"/>. Every endpoint is rooted under
/// <c>/api/files</c> and translates the well-known file system faults
/// (<see cref="ArgumentException"/>, <see cref="UnauthorizedAccessException"/>,
/// <see cref="DirectoryNotFoundException"/>, <see cref="FileNotFoundException"/>
/// and <see cref="IOException"/>) into a <c>400 Bad Request</c> carrying the
/// exception message, leaving any other exception type to propagate.
/// </summary>
[ApiController]
[Route("api/[controller]")]
public class FilesController : ControllerBase
{
    private readonly IFileService _service;
    private readonly ILogger<FilesController> _logger;

    /// <summary>
    /// Creates a new <see cref="FilesController"/> bound to the supplied
    /// <paramref name="service"/> and <paramref name="logger"/>.
    /// </summary>
    public FilesController(IFileService service, ILogger<FilesController> logger)
    {
        _service = service;
        _logger = logger;
    }

    // =====================================================================
    // Browse
    // =====================================================================

    /// <summary>
    /// Lists the immediate children of the directory at <paramref name="path"/>
    /// (the root when omitted or empty), returning directories first then
    /// files, each group sorted by name.
    /// </summary>
    [HttpGet("browse")]
    public ActionResult<BrowseResultDto> Browse([FromQuery] string? path)
    {
        try
        {
            return Ok(_service.Browse(path ?? string.Empty));
        }
        catch (ArgumentException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (UnauthorizedAccessException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (DirectoryNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (FileNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (IOException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }

    // =====================================================================
    // Search
    // =====================================================================

    /// <summary>
    /// Recursively searches under <paramref name="path"/> (the root when
    /// omitted or empty) for entries whose name contains <paramref name="query"/>
    /// (case-insensitive).
    /// </summary>
    [HttpGet("search")]
    public ActionResult<SearchResultDto> Search([FromQuery] string query, [FromQuery] string? path)
    {
        try
        {
            return Ok(_service.Search(query ?? string.Empty, path ?? string.Empty));
        }
        catch (ArgumentException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (UnauthorizedAccessException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (DirectoryNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (FileNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (IOException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }

    // =====================================================================
    // Upload
    // =====================================================================

    /// <summary>
    /// Writes the uploaded <paramref name="file"/> into the directory at
    /// <paramref name="path"/> (the root when omitted or empty), creating it
    /// if necessary. The response reports the joined relative path of the
    /// stored file.
    /// </summary>
    [HttpPost("upload")]
    public async Task<IActionResult> Upload([FromQuery] string? path, [FromForm] IFormFile file)
    {
        try
        {
            await _service.UploadAsync(path ?? string.Empty, file);
        }
        catch (ArgumentException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (UnauthorizedAccessException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (DirectoryNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (FileNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (IOException ex)
        {
            return BadRequest(new { error = ex.Message });
        }

        return Ok(new { path = string.IsNullOrEmpty(path) ? file.FileName : $"{path}/{file.FileName}" });
    }

    // =====================================================================
    // Download
    // =====================================================================

    /// <summary>
    /// Streams the file at <paramref name="path"/> as a physical file
    /// response, deriving the content type from the extension (defaulting to
    /// <c>application/octet-stream</c> when unknown).
    /// </summary>
    [HttpGet("download")]
    public IActionResult Download([FromQuery] string path)
    {
        string full;
        try
        {
            full = _service.ResolveFullPath(path);
        }
        catch (ArgumentException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (UnauthorizedAccessException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (DirectoryNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (FileNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (IOException ex)
        {
            return BadRequest(new { error = ex.Message });
        }

        var contentType = new FileExtensionContentTypeProvider().TryGetContentType(full, out var ct)
            ? ct
            : "application/octet-stream";

        return PhysicalFile(full, contentType, Path.GetFileName(full));
    }

    // =====================================================================
    // Delete
    // =====================================================================

    /// <summary>
    /// Deletes the file or directory (recursively) at <paramref name="path"/>.
    /// </summary>
    [HttpDelete("delete")]
    public IActionResult Delete([FromQuery] string path)
    {
        try
        {
            _service.Delete(path);
        }
        catch (ArgumentException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (UnauthorizedAccessException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (DirectoryNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (FileNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (IOException ex)
        {
            return BadRequest(new { error = ex.Message });
        }

        return Ok(new { success = true });
    }

    // =====================================================================
    // Move
    // =====================================================================

    /// <summary>
    /// Moves the file or directory at <paramref name="request"/>'s
    /// <see cref="MoveRequest.SourcePath"/> to its
    /// <see cref="MoveRequest.DestinationPath"/>.
    /// </summary>
    [HttpPost("move")]
    public IActionResult Move([FromBody] MoveRequest request)
    {
        try
        {
            _service.Move(request);
        }
        catch (ArgumentException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (UnauthorizedAccessException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (DirectoryNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (FileNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (IOException ex)
        {
            return BadRequest(new { error = ex.Message });
        }

        return Ok(new { success = true });
    }

    // =====================================================================
    // Copy
    // =====================================================================

    /// <summary>
    /// Copies the file or directory at <paramref name="request"/>'s
    /// <see cref="CopyRequest.SourcePath"/> to its
    /// <see cref="CopyRequest.DestinationPath"/>.
    /// </summary>
    [HttpPost("copy")]
    public IActionResult Copy([FromBody] CopyRequest request)
    {
        try
        {
            _service.Copy(request);
        }
        catch (ArgumentException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (UnauthorizedAccessException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (DirectoryNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (FileNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (IOException ex)
        {
            return BadRequest(new { error = ex.Message });
        }

        return Ok(new { success = true });
    }
}

using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Options;
using TestProject.Models;

namespace TestProject.Services;

/// <summary>
/// Path-safe implementation of <see cref="IFileService"/> that confines every
/// operation to a single home directory computed once at construction time.
/// Any relative path that normalizes to a location outside the home root causes
/// an <see cref="ArgumentException"/> to be thrown before any disk access.
/// </summary>
public sealed class FileService : IFileService
{
    private const int MaxSearchResults = 500;

    private readonly string _root;

    public FileService(IOptions<FileServiceOptions> options, IWebHostEnvironment env)
    {
        var root = Path.GetFullPath(Path.Combine(env.ContentRootPath, options.Value.HomeDirectory ?? "Home"));
        Directory.CreateDirectory(root);
        _root = root;
    }

    // =====================================================================
    // IFileService
    // =====================================================================

    /// <inheritdoc />
    public BrowseResultDto Browse(string relativePath)
    {
        var full = SafeResolve(relativePath);
        var relative = ToRelative(full);

        var directoryPaths = Directory.GetDirectories(full);
        var filePaths = Directory.GetFiles(full);

        var entries = new List<FileEntryDto>(directoryPaths.Length + filePaths.Length);

        foreach (var dir in directoryPaths)
        {
            var info = new DirectoryInfo(dir);
            entries.Add(new FileEntryDto(
                Name: info.Name,
                Path: ToRelative(dir),
                IsDirectory: true,
                Size: 0,
                LastModified: info.LastWriteTimeUtc));
        }

        foreach (var file in filePaths)
        {
            var info = new FileInfo(file);
            entries.Add(new FileEntryDto(
                Name: info.Name,
                Path: ToRelative(file),
                IsDirectory: false,
                Size: info.Length,
                LastModified: info.LastWriteTimeUtc));
        }

        // Directories first, then files, each group sorted by name (OrdinalIgnoreCase).
        entries.Sort(CompareEntries);

        var folderCount = 0;
        var fileCount = 0;
        var totalSize = 0L;
        foreach (var entry in entries)
        {
            if (entry.IsDirectory)
            {
                folderCount++;
            }
            else
            {
                fileCount++;
                totalSize += entry.Size;
            }
        }

        var parent = ComputeParent(relative);

        return new BrowseResultDto(relative, parent, entries, folderCount, fileCount, totalSize);
    }

    /// <inheritdoc />
    public SearchResultDto Search(string query, string relativePath)
    {
        var full = SafeResolve(relativePath);
        var relative = ToRelative(full);

        var results = new List<FileEntryDto>(MaxSearchResults);

        var stack = new Stack<string>();
        stack.Push(full);

        while (stack.Count > 0 && results.Count < MaxSearchResults)
        {
            var current = stack.Pop();

            string[] subdirectories;
            string[] files;
            try
            {
                subdirectories = Directory.GetDirectories(current);
                files = Directory.GetFiles(current);
            }
            catch (UnauthorizedAccessException)
            {
                continue;
            }
            catch (DirectoryNotFoundException)
            {
                continue;
            }

            foreach (var dir in subdirectories)
            {
                if (results.Count >= MaxSearchResults)
                {
                    break;
                }

                var info = new DirectoryInfo(dir);
                if (info.Name.Contains(query, StringComparison.OrdinalIgnoreCase))
                {
                    results.Add(new FileEntryDto(
                        Name: info.Name,
                        Path: ToRelative(dir),
                        IsDirectory: true,
                        Size: 0,
                        LastModified: info.LastWriteTimeUtc));
                }

                stack.Push(dir);
            }

            foreach (var file in files)
            {
                if (results.Count >= MaxSearchResults)
                {
                    break;
                }

                var info = new FileInfo(file);
                if (info.Name.Contains(query, StringComparison.OrdinalIgnoreCase))
                {
                    results.Add(new FileEntryDto(
                        Name: info.Name,
                        Path: ToRelative(file),
                        IsDirectory: false,
                        Size: info.Length,
                        LastModified: info.LastWriteTimeUtc));
                }
            }
        }

        return new SearchResultDto(query, relative, results);
    }

    /// <inheritdoc />
    public string ResolveFullPath(string relativePath) => SafeResolve(relativePath);

    /// <inheritdoc />
    public async Task UploadAsync(string relativeDirPath, IFormFile file)
    {
        var dir = SafeResolve(relativeDirPath);
        Directory.CreateDirectory(dir);

        var path = Path.Combine(dir, file.FileName);
        await using var fs = File.Create(path);
        await file.CopyToAsync(fs);
    }

    /// <inheritdoc />
    public void Delete(string relativePath)
    {
        var path = SafeResolve(relativePath);

        if (Directory.Exists(path))
        {
            Directory.Delete(path, recursive: true);
        }
        else
        {
            File.Delete(path);
        }
    }

    /// <inheritdoc />
    public void Move(MoveRequest request)
    {
        var source = SafeResolve(request.SourcePath);
        var destination = SafeResolve(request.DestinationPath);

        Directory.CreateDirectory(Path.GetDirectoryName(destination)!);

        if (Directory.Exists(source))
        {
            Directory.Move(source, destination);
        }
        else
        {
            File.Move(source, destination);
        }
    }

    /// <inheritdoc />
    public void Copy(CopyRequest request)
    {
        var source = SafeResolve(request.SourcePath);
        var destination = SafeResolve(request.DestinationPath);

        if (Directory.Exists(source))
        {
            CopyDirectory(source, destination);
        }
        else
        {
            File.Copy(source, destination, overwrite: false);
        }
    }

    // =====================================================================
    // Helpers
    // =====================================================================

    /// <summary>
    /// Combines the home root with <paramref name="relativePath"/>, normalizes
    /// the result, and verifies it stays within the root. A null, empty, or
    /// whitespace path resolves to the root itself. Anything that escapes the
    /// root throws <see cref="ArgumentException"/>.
    /// </summary>
    private string SafeResolve(string relativePath)
    {
        if (string.IsNullOrWhiteSpace(relativePath))
        {
            return _root;
        }

        var full = Path.GetFullPath(Path.Combine(_root, relativePath));

        var isRoot = string.Equals(full, _root, StringComparison.Ordinal);
        var isInsideRoot = full.StartsWith(_root + Path.DirectorySeparatorChar, StringComparison.Ordinal);

        if (!isRoot && !isInsideRoot)
        {
            throw new ArgumentException("Invalid path");
        }

        return full;
    }

    /// <summary>
    /// Converts an absolute path inside the root to a forward-slash relative
    /// path. The root itself becomes the empty string.
    /// </summary>
    private string ToRelative(string full)
    {
        return full
            .Substring(_root.Length)
            .TrimStart(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar)
            .Replace('\\', '/');
    }

    /// <summary>
    /// Computes the normalized (forward-slash) parent of a relative path.
    /// Returns <c>null</c> when <paramref name="relative"/> is the root (empty),
    /// or the empty string when the path is a direct child of the root.
    /// </summary>
    private static string? ComputeParent(string relative)
    {
        if (string.IsNullOrEmpty(relative))
        {
            return null;
        }

        var separatorIndex = relative.LastIndexOf('/');
        if (separatorIndex < 0)
        {
            return string.Empty;
        }

        return relative.Substring(0, separatorIndex);
    }

    /// <summary>
    /// Sorts directories before files, ordering each group by name using
    /// <see cref="StringComparison.OrdinalIgnoreCase"/>.
    /// </summary>
    private static int CompareEntries(FileEntryDto a, FileEntryDto b)
    {
        if (a.IsDirectory != b.IsDirectory)
        {
            return a.IsDirectory ? -1 : 1;
        }

        return string.Compare(a.Name, b.Name, StringComparison.OrdinalIgnoreCase);
    }

    /// <summary>
    /// Recursively copies a directory tree, preserving structure. Existing
    /// files are not overwritten, matching the no-overwrite contract of
    /// <see cref="File.Copy(string, string, bool)"/>.
    /// </summary>
    private static void CopyDirectory(string source, string destination)
    {
        Directory.CreateDirectory(destination);

        foreach (var file in Directory.GetFiles(source))
        {
            File.Copy(file, Path.Combine(destination, Path.GetFileName(file)), overwrite: false);
        }

        foreach (var directory in Directory.GetDirectories(source))
        {
            CopyDirectory(directory, Path.Combine(destination, Path.GetFileName(directory)));
        }
    }
}

using Microsoft.AspNetCore.Http;
using TestProject.Models;

namespace TestProject.Services;

/// <summary>
/// Provides path-safe file system operations confined to a configurable
/// home directory. All relative paths are validated so they cannot escape
/// the sandboxed root before any disk access occurs.
/// </summary>
public interface IFileService
{
    /// <summary>
    /// Lists the immediate children of the directory at <paramref name="relativePath"/>,
    /// returning directories first (then files), each sorted by name.
    /// </summary>
    BrowseResultDto Browse(string relativePath);

    /// <summary>
    /// Recursively searches under <paramref name="relativePath"/> for entries
    /// whose name contains <paramref name="query"/> (case-insensitive).
    /// </summary>
    SearchResultDto Search(string query, string relativePath);

    /// <summary>
    /// Resolves a relative path to its absolute, normalized counterpart within
    /// the home root. Used by controllers to stream downloads.
    /// </summary>
    string ResolveFullPath(string relativePath);

    /// <summary>
    /// Writes the uploaded <paramref name="file"/> into the directory at
    /// <paramref name="relativeDirPath"/>, creating it if necessary.
    /// </summary>
    Task UploadAsync(string relativeDirPath, IFormFile file);

    /// <summary>
    /// Deletes the file or directory (recursively) at <paramref name="relativePath"/>.
    /// </summary>
    void Delete(string relativePath);

    /// <summary>
    /// Moves the file or directory at <paramref name="request.SourcePath"/> to
    /// <paramref name="request.DestinationPath"/>.
    /// </summary>
    void Move(MoveRequest request);

    /// <summary>
    /// Copies the file or directory at <paramref name="request.SourcePath"/> to
    /// <paramref name="request.DestinationPath"/>.
    /// </summary>
    void Copy(CopyRequest request);
}

export interface FileEntry {
  name: string;
  path: string;
  isDirectory: boolean;
  size: number;
  lastModified: string;
}

export interface BrowseResult {
  path: string;
  parent: string | null;
  entries: FileEntry[];
  folderCount: number;
  fileCount: number;
  totalSize: number;
}

export interface SearchResult {
  query: string;
  path: string;
  results: FileEntry[];
}

export class ApiClient {
  constructor(private readonly baseUrl: string = '/api/files') {}

  async browse(path: string): Promise<BrowseResult> {
    return this.request<BrowseResult>(
      `${this.baseUrl}/browse?path=${encodeURIComponent(path)}`,
      { method: 'GET' }
    );
  }

  async search(query: string, path: string): Promise<SearchResult> {
    return this.request<SearchResult>(
      `${this.baseUrl}/search?query=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`,
      { method: 'GET' }
    );
  }

  async upload(path: string, file: File): Promise<{ path: string }> {
    const formData = new FormData();
    formData.append('file', file);
    return this.request<{ path: string }>(
      `${this.baseUrl}/upload?path=${encodeURIComponent(path)}`,
      { method: 'POST', body: formData }
    );
  }

  async delete(path: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/delete?path=${encodeURIComponent(path)}`,
      { method: 'DELETE' }
    );
  }

  async move(source: string, destination: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/move`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
      }
    );
  }

  async copy(source: string, destination: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/copy`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
      }
    );
  }

  downloadUrl(path: string): string {
    return `${this.baseUrl}/download?path=${encodeURIComponent(path)}`;
  }

  private async request<T>(url: string, init?: RequestInit): Promise<T> {
    const res = await fetch(url, init);
    if (!res.ok) {
      throw new Error(res.status + ': ' + await res.text());
    }
    return await res.json() as T;
  }
}

/**
 * SPA entry — wires `api`, `router`, and the DOM into a file-browser UI
 * rendered inside a native `<dialog>` widget.
 *
 * Structure (built imperatively via `document.createElement`):
 *
 *   <button class="trigger">Browse Files</button>
 *   <dialog class="browser-dialog">
 *     header    — title <span> + Close <button class="btn">
 *     toolbar   — .breadcrumb + search <input> + <button> + <label> upload
 *     .results  — file/folder <table>
 *     <footer class="status"> — summary line
 *
 * All user-controlled strings (file/folder names, paths) are inserted via
 * `textContent` / element creation — never via `innerHTML` — to prevent HTML
 * injection.
 */
import { ApiClient } from './api.js';
import type { BrowseResult, FileEntry, SearchResult } from './api.js';
import { parseHash, getCurrentRoute, subscribe, toBrowseHash, toSearchHash, navigate } from './router.js';
import type { Route } from './router.js';
import { formatBytes, normalizeRelativePath, joinPath, parentPath, basename, formatDate } from './format.js';

const api = new ApiClient();

/* -------------------------------------------------------------------------
 * Module-level DOM references
 *
 * `startApp` populates these once per mount. `render`, `renderBrowse`, and
 * `renderSearch` (the latter two are exported for direct unit testing) all
 * operate against them, so they always target the most recently mounted app.
 * Tests re-run `startApp` against a fresh container, re-binding these each
 * time.
 * ---------------------------------------------------------------------- */
let resultsEl!: HTMLElement;
let statusEl!: HTMLElement;
let breadcrumbEl!: HTMLElement;
let searchInput!: HTMLInputElement;
let uploadInput!: HTMLInputElement;

/* =========================================================================
 * startApp — build the DOM, wire events, kick off rendering
 * ========================================================================= */

export function startApp(root: HTMLElement): void {
  root.innerHTML = '';

  /* --- Trigger button --- */
  const trigger = document.createElement('button');
  trigger.className = 'trigger';
  trigger.textContent = 'Browse Files';

  /* --- Native <dialog> widget --- */
  const dialog = document.createElement('dialog');
  dialog.className = 'browser-dialog';

  // Header: title span + Close button
  const header = document.createElement('div');
  header.className = 'dialog-header';
  const titleSpan = document.createElement('span');
  titleSpan.textContent = 'File Browser';
  const closeBtn = document.createElement('button');
  closeBtn.className = 'btn';
  closeBtn.type = 'button';
  closeBtn.textContent = 'Close';
  header.append(titleSpan, closeBtn);

  // Toolbar: breadcrumb, search, upload
  const toolbar = document.createElement('div');
  toolbar.className = 'toolbar';
  breadcrumbEl = document.createElement('div');
  breadcrumbEl.className = 'breadcrumb';
  searchInput = document.createElement('input');
  searchInput.type = 'text';
  searchInput.placeholder = 'Search...';
  const searchBtn = document.createElement('button');
  searchBtn.className = 'btn';
  searchBtn.type = 'button';
  searchBtn.textContent = 'Search';
  const uploadLabel = document.createElement('label');
  uploadLabel.className = 'btn';
  uploadLabel.textContent = 'Upload';
  uploadInput = document.createElement('input');
  uploadInput.type = 'file';
  uploadInput.hidden = true;
  uploadInput.multiple = true;
  uploadLabel.append(uploadInput);
  toolbar.append(breadcrumbEl, searchInput, searchBtn, uploadLabel);

  // Results container + status footer
  resultsEl = document.createElement('div');
  resultsEl.className = 'results';
  statusEl = document.createElement('footer');
  statusEl.className = 'status';

  dialog.append(header, toolbar, resultsEl, statusEl);
  root.append(trigger, dialog);

  /* --- Event wiring --- */
  trigger.addEventListener('click', () => dialog.showModal());
  closeBtn.addEventListener('click', () => dialog.close());

  searchBtn.addEventListener('click', doSearch);
  searchInput.addEventListener('keydown', (event: KeyboardEvent) => {
    if (event.key === 'Enter') {
      doSearch();
    }
  });

  uploadInput.addEventListener('change', handleUpload);

  /* --- Route subscription + initial render --- */
  subscribe(render);
  render();
}

/* =========================================================================
 * Toolbar handlers
 * ========================================================================= */

/** Navigate to a search hash for the current input value and browse path. */
function doSearch(): void {
  const path = normalizeRelativePath(getCurrentRoute().path);
  navigate(toSearchHash(searchInput.value.trim(), path));
}

/** Upload every selected file to the current path, then clear + re-render. */
async function handleUpload(): Promise<void> {
  const list = uploadInput.files;
  const files = list ? Array.from(list) : [];
  if (files.length === 0) {
    return;
  }
  const path = normalizeRelativePath(getCurrentRoute().path);
  for (const file of files) {
    await api.upload(path, file);
  }
  // Clear the input so selecting the same file again re-fires `change`.
  uploadInput.value = '';
  render();
}

/* =========================================================================
 * render — route dispatcher
 *
 * Clears the results container synchronously (so a pending/failed fetch never
 * leaves a stale table behind) but does NOT clear the breadcrumb or status
 * here. Clearing those synchronously would remove in-page navigation targets
 * in the middle of a click handler: `navigate()` dispatches `hashchange`
 * synchronously in happy-dom, which would re-enter `render` and wipe the
 * breadcrumb before the click's caller can read the next segment. The
 * breadcrumb/status are instead refreshed by `renderBrowse`/`renderSearch`
 * once data arrives.
 * ========================================================================= */

async function render(): Promise<void> {
  const route = getCurrentRoute();
  resultsEl.innerHTML = '';
  try {
    if (route.view === 'browse') {
      const result = await api.browse(normalizeRelativePath(route.path));
      renderBrowse(result, route);
    } else {
      const result = await api.search(route.query, normalizeRelativePath(route.path));
      renderSearch(result, route);
    }
  } catch (err) {
    // textContent replaces all children, so any stale table is removed too.
    resultsEl.textContent = err instanceof Error
      ? 'Error: ' + err.message
      : 'Error: ' + String(err);
  }
}

/* =========================================================================
 * renderBrowse — table for a BrowseResult
 * ========================================================================= */

export function renderBrowse(result: BrowseResult, route: Route): void {
  void route; // signature per spec; the API result is the source of truth

  // Breadcrumb (clickable cumulative-path segments)
  renderBreadcrumb(result.path);

  // Status footer: "N folders, M files, total S"
  statusEl.textContent =
    result.folderCount + ' folders, ' +
    result.fileCount + ' files, total ' +
    formatBytes(result.totalSize);

  // Results table
  resultsEl.innerHTML = '';
  const table = buildTable(['Name', 'Size', 'Modified', 'Actions']);
  const tbody = table.querySelector('tbody')!;

  if (result.parent !== null) {
    tbody.append(makeParentRow(result.parent));
  }
  for (const entry of result.entries) {
    tbody.append(makeBrowseRow(entry));
  }

  resultsEl.append(table);
}

/* =========================================================================
 * renderSearch — table for a SearchResult
 * ========================================================================= */

export function renderSearch(result: SearchResult, route: Route): void {
  void route;

  // Breadcrumb reflects the search-scope path.
  renderBreadcrumb(result.path);

  // Status footer: 'R results for "q"'
  statusEl.textContent = result.results.length + ' results for "' + result.query + '"';

  // Results table
  resultsEl.innerHTML = '';
  const table = buildTable(['Name', 'Path', 'Size', 'Modified']);
  const tbody = table.querySelector('tbody')!;

  for (const entry of result.results) {
    tbody.append(makeSearchRow(entry));
  }

  resultsEl.append(table);
}

/* =========================================================================
 * DOM-builder helpers
 * ========================================================================= */

/**
 * Build a `<table>` with a `<thead>` (one `<th>` per header label) and an empty
 * `<tbody>`. The caller appends rows to the `<tbody>`.
 */
function buildTable(headers: string[]): HTMLTableElement {
  const table = document.createElement('table');
  const thead = document.createElement('thead');
  const headRow = document.createElement('tr');
  for (const label of headers) {
    const th = document.createElement('th');
    th.textContent = label;
    headRow.append(th);
  }
  thead.append(headRow);
  const tbody = document.createElement('tbody');
  table.append(thead, tbody);
  return table;
}

/**
 * Render clickable breadcrumb segments into `breadcrumbEl`: a leading "Home"
 * link (root) followed by one link per path segment, each navigating to its
 * cumulative path. Separators are plain '/' text spans.
 */
function renderBreadcrumb(path: string): void {
  breadcrumbEl.innerHTML = '';
  const normalized = normalizeRelativePath(path);
  const segments = normalized === '' ? [] : normalized.split('/');

  breadcrumbEl.append(makeNavLink('Home', toBrowseHash('')));

  let cumulative = '';
  for (const segment of segments) {
    cumulative = joinPath(cumulative, segment);
    const separator = document.createElement('span');
    separator.textContent = '/';
    breadcrumbEl.append(separator, makeNavLink(segment, toBrowseHash(cumulative)));
  }
}

/**
 * Build an `<a>` that navigates to `hash` on click. The `href` is set via
 * `setAttribute` (so the raw attribute is preserved exactly — important for
 * download URLs that must not be URL-normalized) and a click handler calls
 * `navigate(hash)` with `preventDefault` so navigation is reliable across DOM
 * implementations. The href also enables middle-click / copy-link support.
 */
function makeNavLink(text: string, hash: string): HTMLAnchorElement {
  const link = document.createElement('a');
  link.setAttribute('href', hash);
  link.textContent = text;
  link.addEventListener('click', (event) => {
    event.preventDefault();
    navigate(hash);
  });
  return link;
}

/** The ".." parent row: a Name cell whose link navigates to the parent path. */
function makeParentRow(parent: string): HTMLTableRowElement {
  const row = document.createElement('tr');
  const nameCell = document.createElement('td');
  nameCell.append(makeNavLink('..', toBrowseHash(parent)));
  const sizeCell = document.createElement('td');
  const modifiedCell = document.createElement('td');
  const actionsCell = document.createElement('td');
  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
  return row;
}

/** One data row in the browse table (a file or folder entry). */
function makeBrowseRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name — directory names are navigation links; file names are plain text.
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    nameCell.textContent = entry.name;
  }

  // Size — em-dash for folders, formatted bytes for files.
  const sizeCell = document.createElement('td');
  sizeCell.textContent = entry.isDirectory ? '—' : formatBytes(entry.size);

  // Modified
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  // Actions
  const actionsCell = document.createElement('td');
  if (!entry.isDirectory) {
    const download = document.createElement('a');
    download.className = 'btn';
    download.setAttribute('href', api.downloadUrl(entry.path));
    download.setAttribute('download', entry.name);
    download.textContent = 'Download';
    actionsCell.append(download);
  }
  actionsCell.append(makeActionButton('Delete', async () => {
    if (!window.confirm('Delete "' + entry.name + '"?')) {
      return;
    }
    await api.delete(entry.path);
    render();
  }));
  actionsCell.append(makeActionButton('Move', async () => {
    const dest = window.prompt('Move to relative destination path:', entry.path);
    if (dest === null) {
      return;
    }
    await api.move(entry.path, normalizeRelativePath(dest));
    render();
  }));
  actionsCell.append(makeActionButton('Copy', async () => {
    const dest = window.prompt('Copy to relative destination path:', entry.path);
    if (dest === null) {
      return;
    }
    await api.copy(entry.path, normalizeRelativePath(dest));
    render();
  }));

  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
  return row;
}

/** Build a `<button class="btn">` with the given label and click handler. */
function makeActionButton(label: string, handler: () => void): HTMLButtonElement {
  const btn = document.createElement('button');
  btn.className = 'btn';
  btn.type = 'button';
  btn.textContent = label;
  btn.addEventListener('click', handler);
  return btn;
}

/** One data row in the search-results table. */
function makeSearchRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name — directories browse into; files open their download URL.
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    const link = document.createElement('a');
    link.setAttribute('href', api.downloadUrl(entry.path));
    link.textContent = entry.name;
    nameCell.append(link);
  }

  // Path
  const pathCell = document.createElement('td');
  pathCell.textContent = entry.path;

  // Size
  const sizeCell = document.createElement('td');
  sizeCell.textContent = formatBytes(entry.size);

  // Modified
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  row.append(nameCell, pathCell, sizeCell, modifiedCell);
  return row;
}

/* =========================================================================
 * Bootstrap
 *
 * Guarded so the module is importable in tests (which have no #app element)
 * without side effects. Only mounts when a real #app container exists.
 * ========================================================================= */

const appRoot = document.getElementById('app');
if (appRoot) {
  startApp(appRoot);
}

/**
 * Tests for `src/app.ts` — the SPA entry that wires `api` + `router` + DOM.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 *
 * This module is being developed test-first, so the assertions below pin the
 * observable contract from the task spec. Where the spec left the exact
 * mechanism open, these contract decisions are encoded and documented inline:
 *
 *  - In-app navigation (directory links, the ".." parent row, breadcrumb
 *    segments, search-result directory names) is verified by asserting on
 *    `window.location.hash` after a click. This is robust to either
 *    implementation strategy: a click handler that calls `navigate(...)`, or an
 *    `<a href="#...">` (happy-dom follows hash-fragment href clicks).
 *  - Clicking a search-result FILE name opens its download URL. The spec does
 *    not pin the mechanism, so that test accepts EITHER an
 *    `<a href={downloadUrl}>` OR a `window.open(downloadUrl)` call.
 *  - The action controls Delete / Move / Copy are `<button>` elements whose
 *    trimmed `textContent` is exactly `"Delete"` / `"Move"` / `"Copy"`.
 *  - `renderBrowse` / `renderSearch` operate against the DOM context that
 *    `startApp` establishes (module-level element references), so every test
 *    calls `setup()` first.
 *  - The results table uses a `<thead>` (header `<th>` row) and a `<tbody>`
 *    (data `<td>` rows). Column order for browse is
 *    `Name | Size | Modified | Actions`; for search `Name | Path | Size |
 *    Modified`.
 */
import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { startApp, renderBrowse, renderSearch } from './app';
import type { BrowseResult, FileEntry, SearchResult } from './api';
import type { Route } from './router';
import { toBrowseHash, toSearchHash, navigate } from './router';
import { normalizeRelativePath, formatBytes } from './format';

/* ===========================================================================
 * Shared helpers
 * ========================================================================= */

/** Minimal fetch `Response` stand-in for the stubbed global `fetch`. */
function mockResponse(opts: {
  ok?: boolean;
  status?: number;
  body?: unknown;
  text?: string;
}): Response {
  const status = opts.status ?? 200;
  const ok = opts.ok ?? (status >= 200 && status < 300);
  const text = opts.text ?? JSON.stringify(opts.body ?? {});
  return {
    ok,
    status,
    text: async () => text,
    json: async () => (opts.body ?? {}),
  } as unknown as Response;
}

const ISO = '2024-03-15T10:30:00'; // offset-free → parsed as local time
const ISO_FMT = '2024-03-15 10:30'; // expected formatDate(...) output

function fileEntry(opts: Partial<FileEntry> & { name: string }): FileEntry {
  return {
    name: opts.name,
    path: opts.path ?? joinPathHelper('docs', opts.name),
    isDirectory: opts.isDirectory ?? false,
    size: opts.size ?? 0,
    lastModified: opts.lastModified ?? ISO,
  };
}

function browseResult(opts: Partial<BrowseResult> = {}): BrowseResult {
  return {
    path: opts.path ?? '',
    parent: opts.parent ?? null,
    entries: opts.entries ?? [],
    folderCount: opts.folderCount ?? 0,
    fileCount: opts.fileCount ?? 0,
    totalSize: opts.totalSize ?? 0,
  };
}

// local join to avoid pulling joinPath into the test's asserted import set
function joinPathHelper(base: string, name: string): string {
  return (base ? base + '/' : '') + name;
}

const browseRoute = (path: string): Route => ({ view: 'browse', path, query: '' });
const searchRoute = (query: string, path = ''): Route => ({ view: 'search', query, path });

/** Let pending microtasks / queued hashchange renders settle. */
const flush = (): Promise<void> => new Promise((r) => setTimeout(r, 0));

interface SetupCtx {
  root: HTMLElement;
  dialog: HTMLDialogElement;
  trigger: HTMLButtonElement;
  closeBtn: HTMLButtonElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
  searchBtn: HTMLButtonElement;
  uploadLabel: HTMLLabelElement;
  uploadInput: HTMLInputElement;
  results: HTMLElement;
  status: HTMLElement;
}

/**
 * Build a fresh app inside a fresh container. Clears `document.body` first so
 * every test is independent (no leakage of elements, and document-scoped
 * queries inside `renderBrowse`/`renderSearch` always resolve to the current
 * test's DOM).
 */
function setup(options: { hash?: string } = {}): SetupCtx {
  document.body.innerHTML = '';
  window.location.hash = options.hash ?? '';

  const root = document.createElement('div');
  document.body.append(root);
  startApp(root);

  const button = (text: string): HTMLButtonElement | undefined =>
    Array.from(root.querySelectorAll('button')).find(
      (b) => (b.textContent ?? '').trim() === text,
    ) as HTMLButtonElement | undefined;

  return {
    root,
    dialog: root.querySelector('dialog.browser-dialog') as HTMLDialogElement,
    trigger: root.querySelector('button.trigger') as HTMLButtonElement,
    closeBtn: button('Close') as HTMLButtonElement,
    breadcrumb: root.querySelector('.breadcrumb') as HTMLElement,
    searchInput: root.querySelector('input[type="text"]') as HTMLInputElement,
    searchBtn: button('Search') as HTMLButtonElement,
    uploadLabel: root.querySelector('label.btn') as HTMLLabelElement,
    uploadInput: root.querySelector('input[type="file"]') as HTMLInputElement,
    results: root.querySelector('.results') as HTMLElement,
    status: root.querySelector('.status') as HTMLElement,
  };
}

/**
 * `setup()` plus a flush (so startApp's initial `render()` settles) and a clear
 * of `.results`, mimicking what `render()` does before delegating to
 * `renderBrowse`/`renderSearch`. Used by tests that exercise those helpers
 * directly so their assertions are isolated from the initial render's output.
 */
async function setupCleared(options: { hash?: string } = {}): Promise<SetupCtx> {
  const ctx = setup(options);
  await flush();
  ctx.results.innerHTML = '';
  return ctx;
}

/* Table-traversal helpers (browser-agnostic; work on Element). */
function dataRows(table: Element): Element[] {
  return Array.from(table.querySelectorAll('tbody tr'));
}
function rowByName(table: Element, name: string): Element | undefined {
  return dataRows(table).find(
    (tr) => (tr.querySelector('td')?.textContent ?? '').trim() === name,
  );
}
function cellsOf(row: Element): Element[] {
  return Array.from(row.querySelectorAll('td'));
}
function clickNameLink(row: Element): void {
  const nameCell = cellsOf(row)[0];
  const link = nameCell.querySelector('a, button') as HTMLElement | null;
  (link ?? (nameCell as HTMLElement)).click();
}
function buttonsByText(container: Element, text: string): HTMLButtonElement[] {
  return Array.from(container.querySelectorAll('button')).filter(
    (b) => (b.textContent ?? '').trim() === text,
  );
}

/* ===========================================================================
 * Test lifecycle
 * ========================================================================= */

let fetchMock: ReturnType<typeof vi.fn>;

beforeEach(() => {
  // A permissive default: every browse/search GET returns a recognizable result
  // derived from the requested path/query, and every mutation returns 200.
  // Individual tests override with `fetchMock.mockImplementation(...)` or
  // `.mockResolvedValueOnce(...)` for specific scenarios. This also means
  // incidental background renders (e.g. from accumulated hashchange listeners)
  // never throw unhandled rejections.
  fetchMock = vi.fn(async (url: string, init?: RequestInit) => {
    const u = String(url);
    const method = (init?.method ?? 'GET').toUpperCase();
    if (method === 'GET' && u.includes('/browse')) {
      const raw = u.split('path=')[1] ?? '';
      const path = decodeURIComponent(raw);
      const childName = 'child-of-' + (path || 'root');
      return mockResponse({
        body: browseResult({
          path,
          entries: [fileEntry({ name: childName, path: joinPathHelper(path, childName) })],
          fileCount: 1,
          totalSize: 10,
        }),
      });
    }
    if (method === 'GET' && u.includes('/search')) {
      const afterQuery = u.slice(u.indexOf('query=') + 6);
      const query = decodeURIComponent(afterQuery.split('&')[0]);
      return mockResponse({
        body: {
          query,
          path: '',
          results: [fileEntry({ name: 'result-for-' + query, path: joinPathHelper('docs', 'result-for-' + query) })],
        } as SearchResult,
      });
    }
    return mockResponse({ status: 200, body: {} });
  });
  vi.stubGlobal('fetch', fetchMock);
});

afterEach(() => {
  // NOTE: do NOT touch window.location.hash here. In happy-dom, assigning to
  // location.hash dispatches `hashchange` synchronously, and startApp
  // subscribes a render() listener that is never unsubscribed. Resetting the
  // hash after `vi.unstubAllGlobals()` would therefore drive a render through
  // the REAL fetch. We clear the body first (while fetch is still stubbed, so
  // any in-flight render's already-issued request stays mocked) and reset the
  // hash at the start of the next test's setup() instead.
  document.body.innerHTML = '';
  vi.unstubAllGlobals();
  vi.restoreAllMocks();
});

/* ===========================================================================
 * Module surface / bootstrap guard
 * ========================================================================= */
describe('app module surface', () => {
  it('exports startApp, renderBrowse, and renderSearch as functions', () => {
    expect(typeof startApp).toBe('function');
    expect(typeof renderBrowse).toBe('function');
    expect(typeof renderSearch).toBe('function');
  });

  it('can be imported without a DOM #app element present (bootstrap is guarded)', () => {
    // Importing this test file already imported './app'. That import ran the
    // bootstrap line `const root = document.getElementById('app'); if (root)
    // startApp(root);` against an empty document and did not throw — reaching
    // this assertion proves the guard. We additionally assert there is no
    // stray dialog created at module load time.
    expect(document.querySelector('dialog.browser-dialog')).toBeNull();
  });
});

/* ===========================================================================
 * startApp — DOM structure & dialog wiring
 * ========================================================================= */
describe('startApp', () => {
  describe('DOM structure', () => {
    it('creates a trigger button labelled "Browse Files"', () => {
      const { trigger } = setup();
      expect(trigger).toBeTruthy();
      expect(trigger.className).toBe('trigger');
      expect(trigger.textContent?.trim()).toBe('Browse Files');
    });

    it('creates a native <dialog class="browser-dialog"> that starts closed', () => {
      const { dialog } = setup();
      expect(dialog).toBeTruthy();
      expect(dialog.tagName).toBe('DIALOG');
      expect(dialog.className).toBe('browser-dialog');
      expect(dialog.open).toBe(false);
    });

    it('renders a header with a title span and a Close button', () => {
      const { dialog, closeBtn } = setup();
      expect(closeBtn).toBeTruthy();
      expect(closeBtn.textContent?.trim()).toBe('Close');
      expect(closeBtn.className).toBe('btn');
      expect(dialog.contains(closeBtn)).toBe(true);
